// Obtém o item atual do n8n
let account = $json;

// Mapeamento de status da conta
const accountStatusMap = {
    1: "ACTIVE",
    2: "DISABLED",
    3: "UNSETTLED",
    7: "PENDING_RISK_REVIEW",
    8: "PENDING_SETTLEMENT",
    9: "IN_GRACE_PERIOD",
    100: "PENDING_CLOSURE",
    101: "CLOSED",
    201: "ANY_ACTIVE",
    202: "ANY_CLOSED"
};

// Obtém o nome do status da conta
let statusName = accountStatusMap[account.account_status] || "UNKNOWN";

// Retorna o item atualizado com o nome do status
return {
    json: {
        ...account,
        account_status_name: statusName
    }
};

